1	// Package store provides an in-memory key-value store.
2	package store
3	
4	import (
5		"errors"
6		"sync"
7	)
8	
9	// ErrNotFound is returned when a key does not exist.
10	var ErrNotFound = errors.New("not found")
11	
12	// Store is a thread-safe key-value store.
13	type Store struct {
14		mu    sync.RWMutex
15		items map[string]string
16	}
17	
18	// Reader reads values by key.
19	type Reader interface {
20		Get(key string) (string, error)
21	}
22	
23	// New creates an empty Store.
24	func New() *Store {
25		return &Store{items: make(map[string]string)}
26	}
27	
28	// Get returns the value for key, or ErrNotFound.
29	func (s *Store) Get(key string) (string, error) {
30		s.mu.RLock()
31		defer s.mu.RUnlock()
32		v, ok := s.items[key]
33		if !ok {
34			return "", ErrNotFound
35		}
36		return v, nil
37	}
38	
39	// Set stores value under key.
40	func (s *Store) Set(key, value string) {
41		s.mu.Lock()
42		defer s.mu.Unlock()
43		s.items[key] = normalize(value)
44	}
45	
46	// Len reports the number of stored items.
47	func (s *Store) Len() int {
48		return len(s.items)
49	}
50	
51	// Item is a key-value pair snapshot.
52	type Item struct {
53		Key   string
54		Value string
55	}
56	
57	// Describe renders the item as "key=value".
58	func (i Item) Describe() string {
59		return i.Key + "=" + i.Value
60	}
61	
62	func normalize(v string) string {
63		if v == "" {
64			return "<empty>"
65		}
66		return v
67	}
