14	// Lookup reads through to the backend and counts hits.
15	func (c *Cache) Lookup(key string) (string, error) {
16		v, err := c.backend.Get(key)
17		if err == nil {
18			c.hits++
19		}
20		return v, err
21	}
22	
23	// Warm preloads the cache with pairs.
24	func (c *Cache) Warm(pairs map[string]string) {
25		for k, v := range pairs {
